const staticData = $getWorkflowStaticData('node');

const attempts = staticData.attempts ?? 0;
const newAttempts = attempts + 1;

if (newAttempts >= 3) {
    staticData.attempts = 0; // reset for next execution
    return [{ json: { ...$json, attempts: newAttempts, is_failed: 'yes' } }];
}

staticData.attempts = newAttempts;
return [{ json: { ...$json, attempts: newAttempts, is_failed: 'no' } }];

const output = $json.output || '';

const requiredKeywords = [
    ['Production', 'Processus de production'],
    ['Infrastructure'],
    ['Human Resources', 'Ressources humaines'],
    ['Calendar', 'Calendrier'],
];

const missingKeywords = requiredKeywords.filter(group =>
    !group.some(kw => output.toLowerCase().includes(kw.toLowerCase()))
);

return [{
    json: {
        ...$json,
        keywords_valid: missingKeywords.length === 0 ? 'true' : 'false',
        missing_keywords: missingKeywords.map(g => g[0]),
    }
}];

const output = $json.output || '';
const minLength = 400;
const length_valid = output.length >= minLength ? 'true' : 'false';

return [{
  json: {
    ...$json,
    length_valid: length_valid,
    actual_length: output.length,
  }
}];

const body = $json.body || $json;
const sectionId = body.section_id;
const input = body.input_json || {};
const context = body.plan_context || {};
const language = body.language || 'english';
const businessPlanId = body.business_plan_id;

const headings = language === 'french' ? `
- Processus de production
- Infrastructure
- Ressources humaines
- Calendrier
` : `
- Production Process
- Infrastructure
- Human Resources
- Calendar
`;

const prompt = `
You are a senior operations manager writing a professional business plan.

Your task: Write the "Operational Plan" section of a business plan.
Output language: ${language}

## COMPANY CONTEXT
${context.company_presentation || 'Not provided'}

## ORGANIZATION CONTEXT
${context.org_management || 'Not provided'}

## STRATEGY CONTEXT
${context.strategy || 'Not provided'}

## OPERATIONS INPUT DATA
- Production Process: ${input.production_process || 'Not provided'}
- Infrastructure: ${input.infrastructure || 'Not provided'}
- Logistics: ${input.logistics || 'Not provided'}
- Hiring Plan: ${input.hiring_plan || 'Not provided'}
- Calendar: ${input.calendar || 'Not provided'}
- Operational KPIs: ${input.operational_kpis || 'Not provided'}

## RULES
- Use ONLY the data provided above. Do NOT invent processes, costs, timelines, or headcount figures.
- For any field marked "Not provided", write: "This operational element will be specified during the implementation phase."
- The operational plan MUST serve the strategy: hiring, infrastructure, and delivery model must directly enable the revenue streams and sales channels defined in the strategy context.
- Milestones in the calendar MUST be sequenced logically — earlier milestones enable later ones.
- KPIs MUST be measurable and tied to the delivery model described.
- Write at least 400 words.
- Use formal, operational business language throughout.
- Structure the section using these headings: ${headings}
- Milestones MUST cover the full roadmap horizon established in the Strategy context. If the strategy mentions features or launches planned for future years (e.g. mobile app, AI features), those MUST appear as later-stage milestones in the calendar — do not stop at the earliest phase only.
- NEVER repeat a sentence, phrase, or paragraph already written earlier in your response. Each paragraph MUST introduce new information.

## OUTPUT FORMAT
Return your response using EXACTLY this structure. Nothing before. Nothing after.

=== SECTION_TEXT ===
[Write the full Operational Plan section here, using the headings above]

=== MEMORY_SUMMARY ===
Delivery Model: [physical / digital / hybrid — inferred from production process and logistics, or "Not provided"]
Infrastructure: [key tools, facilities, or platforms listed, or "Not provided"]
Key Milestones: [top 2–3 milestones with dates or phases, or "Not provided"]
Hiring Plan: [total headcount target and key roles, or "Not provided"]
KPIs: [top 3 measurable KPIs, or "Not provided"]
`;

return [{
  json: {
    prompt,
    sectionId: sectionId,
    business_plan_id: businessPlanId,
    section_name: 'operational_plan',
    language,
    input_json: input,
  }
}];

const raw = $('AI Agent').item.json.output || '';

let textMatch = raw.match(/=== SECTION_TEXT ===([\s\S]*?)=== MEMORY_SUMMARY ===/);
let memMatch  = raw.match(/=== MEMORY_SUMMARY ===([\s\S]*?)$/);

if (!textMatch) {
  const parts = raw.split(/===\s*MEMORY_SUMMARY\s*===/i);
  textMatch = parts.length > 1 ? [null, parts[0].replace(/===.*?===/i, '').trim()] : null;
}
if (!memMatch) {
  const parts = raw.split(/===\s*MEMORY_SUMMARY\s*===/i);
  memMatch = parts.length > 1 ? [null, parts[1].trim()] : null;
}

let section_text   = textMatch ? textMatch[1].replace(/^===.*?===\n?/i, '').trim() : raw.trim();
section_text = section_text.replace(/===\s*[^=]*?\s*===/g, '').trim();
const memory_summary = memMatch ? memMatch[1].trim() : '';

const promptText   = $('Build Prompt').item.json.prompt || '';
const tokens_input  = Math.round(promptText.length / 4);
const tokens_output = Math.round(raw.length / 4);
const tokens_total  = tokens_input + tokens_output;

const buildData = $('Build Prompt').item.json;
return [{
  json: {
    ...buildData,
    output: section_text,
    memory_summary,
    tokens_input,
    tokens_output,
    tokens_total,
  }
}];
